--
-- Table structure for table `caipiao_lottery_play_types`
--

DROP TABLE IF EXISTS `caipiao_lottery_play_types`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_lottery_play_types` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `lottery_code` varchar(50) NOT NULL COMMENT 'loại xổ sốmã',
  `play_type` varchar(50) NOT NULL COMMENT 'loại cượcLoại',
  `play_name` varchar(100) NOT NULL COMMENT 'tên loại cược',
  `category` varchar(50) DEFAULT NULL COMMENT 'danh mụcliangmian/hezhi/quwei',
  `odds` decimal(10,2) NOT NULL DEFAULT '1.00' COMMENT 'tỷ lệ',
  `min_bet` decimal(10,2) NOT NULL DEFAULT '1.00' COMMENT 'tối thiểuđặt cược',
  `max_bet` decimal(10,2) NOT NULL DEFAULT '100000.00' COMMENT 'tối đađặt cược',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Trạng thái0-Vô hiệu hóa 1-Kích hoạt',
  `sort` int(11) NOT NULL DEFAULT '0' COMMENT 'Sắp xếp',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_lottery_code` (`lottery_code`),
  KEY `idx_play_type` (`play_type`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=152 DEFAULT CHARSET=utf8mb4 COMMENT='Xổ sốCách chơiLoạiCấu hìnhBảng';
/*!40101 SET character_set_client = @saved_cs_client */;

